blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>najważniejsze formy pytań</strong> w języku angielskim oraz podstawowe zasady ich budowy.",
    "rules": [
        {
            "label": "YES / NO QUESTIONS",
            "color": "emerald",
            "text": "<strong>Pytania ogólne</strong> wymagają odpowiedzi „tak” albo „nie”:",
            "example": "Do you like tea? / Are you ready?"
        },
        {
            "label": "WH-QUESTIONS",
            "color": "blue",
            "text": "<strong>Pytania szczegółowe</strong> zaczynają się od słowa pytającego:",
            "example": "What do you want? / Where are you going?"
        },
        {
            "label": "SZYK SŁÓW",
            "color": "amber",
            "text": "W pytaniach bardzo często pojawia się <strong>inwersja</strong>, czyli czasownik pomocniczy przed podmiotem:",
            "example": "Auxiliary + subject + main verb"
        }
    ]
}

{
    "title": "1. Jakie pytania tu ćwiczysz?",
    "intro": "W tej sekcji pracujesz z głównymi modelami pytań w języku angielskim:",
    "items": [
        {
            "label": "Yes / No",
            "title": "Pytania ogólne",
            "subtitle": "Odpowiedź: yes albo no"
        },
        {
            "label": "Wh",
            "title": "Wh-Questions",
            "subtitle": "Pytania z who, what, where, when, why, how"
        },
        {
            "label": "Answers",
            "title": "Answers to Questions",
            "subtitle": "Krótkie i pełne odpowiedzi"
        },
        {
            "label": "Alternative",
            "title": "Alternative Questions",
            "subtitle": "Wybór między opcjami"
        },
        {
            "label": "Tags",
            "title": "Question Tags",
            "subtitle": "Krótki tag na końcu zdania"
        },
        {
            "label": "Negative",
            "title": "Negative Questions",
            "subtitle": "Pytania z formą przeczącą"
        }
    ]
}

{
    "title": "2. Podstawowa kolejność słów w pytaniach",
    "sections": [
        {
            "label": "Inwersja podmiotu i czasownika",
            "color": "emerald",
            "description": "W większości pytań <strong>czasownik pomocniczy stoi przed podmiotem</strong>. To właśnie nazywamy inwersją.",
            "examples": [
                {
                    "en": "You are ready. → Are you ready?",
                    "ua": "Jesteś gotowy. → Czy jesteś gotowy?"
                },
                {
                    "en": "She can swim. → Can she swim?",
                    "ua": "Ona umie pływać. → Czy ona umie pływać?"
                },
                {
                    "en": "They will come. → Will they come?",
                    "ua": "Oni przyjdą. → Czy oni przyjdą?"
                }
            ]
        },
        {
            "label": "Ogólna formuła pytania",
            "color": "blue",
            "description": "Typowa struktura pytania w języku angielskim wygląda tak:",
            "examples": [
                {
                    "en": "Auxiliary + subject + main verb + ...?",
                    "ua": "Czasownik pomocniczy + podmiot + czasownik główny + ...?"
                },
                {
                    "en": "Do you speak English?",
                    "ua": "Czy mówisz po angielsku?"
                },
                {
                    "en": "Will he come tonight?",
                    "ua": "Czy on przyjdzie dziś wieczorem?"
                }
            ],
            "note": "📌 Jeśli w zdaniu jest czasownik pomocniczy, to właśnie on zwykle przechodzi przed podmiot."
        }
    ]
}

{
    "title": "3. Pytania ogólne",
    "sections": [
        {
            "label": "Z DO/DOES/DID",
            "color": "emerald",
            "description": "W czasach prostych z czasownikiem głównym używamy <strong>do/does/did</strong>.",
            "examples": [
                {
                    "en": "Do you like coffee?",
                    "ua": "Czy lubisz kawę?"
                },
                {
                    "en": "Does she work here?",
                    "ua": "Czy ona tu pracuje?"
                },
                {
                    "en": "Did they arrive on time?",
                    "ua": "Czy oni przyjechali na czas?"
                }
            ]
        },
        {
            "label": "Z TO BE",
            "color": "sky",
            "description": "Z czasownikiem <strong>to be</strong> po prostu przestawiamy jego formę przed podmiot.",
            "examples": [
                {
                    "en": "Are you ready?",
                    "ua": "Czy jesteś gotowy?"
                },
                {
                    "en": "Is she at home?",
                    "ua": "Czy ona jest w domu?"
                },
                {
                    "en": "Were they happy?",
                    "ua": "Czy oni byli szczęśliwi?"
                }
            ]
        },
        {
            "label": "Z modalnymi",
            "color": "purple",
            "description": "Po modalach także stosujemy inwersję.",
            "examples": [
                {
                    "en": "Can you swim?",
                    "ua": "Czy umiesz pływać?"
                },
                {
                    "en": "Will she come?",
                    "ua": "Czy ona przyjdzie?"
                },
                {
                    "en": "Should we wait?",
                    "ua": "Czy powinniśmy poczekać?"
                }
            ]
        }
    ]
}

{
    "title": "4. Wh-questions",
    "sections": [
        {
            "label": "Słowa pytające",
            "color": "emerald",
            "description": "Pytania szczegółowe zaczynają się od słowa pytającego.",
            "examples": [
                {
                    "en": "What do you want?",
                    "ua": "Czego chcesz?"
                },
                {
                    "en": "Where are you going?",
                    "ua": "Dokąd idziesz?"
                },
                {
                    "en": "When did they arrive?",
                    "ua": "Kiedy oni przyjechali?"
                },
                {
                    "en": "Why is she crying?",
                    "ua": "Dlaczego ona płacze?"
                },
                {
                    "en": "Who called you?",
                    "ua": "Kto do ciebie dzwonił?"
                },
                {
                    "en": "How do you know?",
                    "ua": "Skąd wiesz?"
                }
            ]
        },
        {
            "label": "Struktura pytania Wh",
            "color": "blue",
            "description": "Najczęstszy schemat wygląda tak:",
            "examples": [
                {
                    "en": "Wh-word + auxiliary + subject + main verb + ...?",
                    "ua": "Słowo pytające + czasownik pomocniczy + podmiot + czasownik główny + ...?"
                },
                {
                    "en": "What do you want?",
                    "ua": "Czego chcesz?"
                },
                {
                    "en": "Where is she going?",
                    "ua": "Dokąd ona idzie?"
                },
                {
                    "en": "Why did they leave?",
                    "ua": "Dlaczego oni wyszli?"
                }
            ]
        },
        {
            "label": "Pytania o podmiot",
            "color": "amber",
            "description": "Gdy <strong>who</strong> albo <strong>what</strong> jest podmiotem, nie używamy <strong>do/does/did</strong>.",
            "examples": [
                {
                    "en": "Who called you?",
                    "ua": "Kto do ciebie dzwonił?"
                },
                {
                    "en": "What happened?",
                    "ua": "Co się stało?"
                },
                {
                    "en": "Who knows the answer?",
                    "ua": "Kto zna odpowiedź?"
                }
            ],
            "note": "📌 Jeśli pytasz o podmiot, po słowie pytającym od razu pojawia się czasownik."
        }
    ]
}

{
    "title": "5. Czasowniki pomocnicze w pytaniach",
    "sections": [
        {
            "label": "DO/DOES/DID",
            "color": "emerald",
            "description": "Używamy ich z głównymi czasownikami w czasach prostych.",
            "examples": [
                {
                    "en": "Present Simple: do / does",
                    "ua": "Do you live here? / Does she work here?"
                },
                {
                    "en": "Past Simple: did",
                    "ua": "Did they leave? / Did you see it?"
                }
            ],
            "note": "📌 Po <strong>does</strong> i <strong>did</strong> główny czasownik pozostaje w formie podstawowej."
        },
        {
            "label": "TO BE",
            "color": "sky",
            "description": "Z <strong>to be</strong> nie potrzebujemy <strong>do/does/did</strong>.",
            "examples": [
                {
                    "en": "Present: am / is / are",
                    "ua": "Are you ready? / Is she here?"
                },
                {
                    "en": "Past: was / were",
                    "ua": "Was he at home? / Were they happy?"
                }
            ]
        },
        {
            "label": "HAVE / HAS",
            "color": "purple",
            "description": "W czasach perfect pomocniczym jest <strong>have</strong> albo <strong>has</strong>.",
            "examples": [
                {
                    "en": "Present Perfect: have / has",
                    "ua": "Have you seen it? / Has she finished?"
                },
                {
                    "en": "Past Perfect: had",
                    "ua": "Had they left before you arrived?"
                }
            ]
        },
        {
            "label": "Modale",
            "color": "amber",
            "description": "Modalne czasowniki same przechodzą przed podmiot.",
            "examples": [
                {
                    "en": "Can / could",
                    "ua": "Can you help? / Could she come?"
                },
                {
                    "en": "Will / would",
                    "ua": "Will they arrive? / Would you like some tea?"
                },
                {
                    "en": "Should / must / may",
                    "ua": "Should I wait? / Must we go? / May I ask?"
                }
            ]
        }
    ]
}

{
    "title": "6. Pytania w różnych czasach",
    "sections": [
        {
            "label": "Present Simple",
            "color": "emerald",
            "description": "Używamy <strong>do/does</strong>, a z <strong>to be</strong> po prostu odwracamy kolejność.",
            "examples": [
                {
                    "en": "Do you speak English?",
                    "ua": "Czy mówisz po angielsku?"
                },
                {
                    "en": "Does she live here?",
                    "ua": "Czy ona tu mieszka?"
                },
                {
                    "en": "Are you a student?",
                    "ua": "Czy jesteś studentem?"
                }
            ]
        },
        {
            "label": "Present Continuous",
            "color": "sky",
            "description": "W Present Continuous pomocnicze <strong>am/is/are</strong> przechodzi przed podmiot.",
            "examples": [
                {
                    "en": "Are you working now?",
                    "ua": "Czy teraz pracujesz?"
                },
                {
                    "en": "Is she coming?",
                    "ua": "Czy ona przychodzi?"
                },
                {
                    "en": "What are they doing?",
                    "ua": "Co oni robią?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "purple",
            "description": "W Past Simple używamy <strong>did</strong>, a z <strong>to be</strong> — <strong>was/were</strong>.",
            "examples": [
                {
                    "en": "Did you see the film?",
                    "ua": "Czy widziałeś ten film?"
                },
                {
                    "en": "Where did she go?",
                    "ua": "Dokąd ona poszła?"
                },
                {
                    "en": "Were you at home?",
                    "ua": "Czy byłeś w domu?"
                }
            ]
        },
        {
            "label": "Present Perfect",
            "color": "amber",
            "description": "W Present Perfect pomocnicze <strong>have/has</strong> stoi przed podmiotem.",
            "examples": [
                {
                    "en": "Have you ever been to Paris?",
                    "ua": "Czy byłeś kiedyś w Paryżu?"
                },
                {
                    "en": "Has she finished her work?",
                    "ua": "Czy ona skończyła swoją pracę?"
                },
                {
                    "en": "What have they done?",
                    "ua": "Co oni zrobili?"
                }
            ]
        },
        {
            "label": "Future Simple",
            "color": "rose",
            "description": "W Future Simple stosujemy inwersję z <strong>will</strong>.",
            "examples": [
                {
                    "en": "Will you come to the party?",
                    "ua": "Czy przyjdziesz na imprezę?"
                },
                {
                    "en": "When will she arrive?",
                    "ua": "Kiedy ona przyjedzie?"
                },
                {
                    "en": "What will they do?",
                    "ua": "Co oni zrobią?"
                }
            ]
        }
    ]
}

{
    "title": "7. Porównanie typów pytań",
    "intro": "Najważniejsze modele pytań w języku angielskim:",
    "rows": [
        {
            "en": "Yes / No Questions",
            "ua": "Pytania ogólne",
            "note": "Do you like tea? — odpowiedź yes / no"
        },
        {
            "en": "Wh-Questions",
            "ua": "Pytania szczegółowe",
            "note": "What do you want? — konkretna informacja"
        },
        {
            "en": "Answers to Questions",
            "ua": "Odpowiedzi na pytania",
            "note": "Yes, I do. / No, she isn't."
        },
        {
            "en": "Alternative Questions",
            "ua": "Pytania alternatywne",
            "note": "Tea or coffee? — wybór między opcjami"
        },
        {
            "en": "Question Tags",
            "ua": "Question tags",
            "note": "You like it, don't you? — potwierdzenie"
        },
        {
            "en": "Negative Questions",
            "ua": "Pytania przeczące",
            "note": "Don't you know? — zdziwienie albo oczekiwanie"
        }
    ],
    "warning": "📌 Każdy typ pytania ma własną strukturę i własny efekt komunikacyjny."
}

{
    "title": "8. Kiedy używać do/does/did",
    "intro": "Najważniejsze zasady związane z <strong>do/does/did</strong>:",
    "rows": [
        {
            "en": "Simple tenses with main verbs",
            "ua": "Czasy proste z głównymi czasownikami",
            "note": "Do you work? / Does she know? / Did they leave?"
        },
        {
            "en": "NOT with TO BE",
            "ua": "Nie z to be",
            "note": "❌ Do you are happy? → ✅ Are you happy?"
        },
        {
            "en": "NOT with modals",
            "ua": "Nie z modalnymi",
            "note": "❌ Do you can swim? → ✅ Can you swim?"
        },
        {
            "en": "NOT with perfect tenses",
            "ua": "Nie w czasach perfect",
            "note": "❌ Did you have seen it? → ✅ Have you seen it?"
        },
        {
            "en": "NOT in subject questions",
            "ua": "Nie w pytaniach o podmiot",
            "note": "❌ Who did call? → ✅ Who called?"
        }
    ],
    "warning": "⚠️ <strong>Do/does/did</strong> używamy tylko tam, gdzie naprawdę są potrzebne."
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zła kolejność słów w pytaniu.",
            "wrong": "❌ You are happy?",
            "right": "✅ <span class=\"font-mono\">Are you happy?</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Dodawanie <strong>do/does</strong> do czasownika <strong>to be</strong>.",
            "wrong": "❌ Do you are ready?",
            "right": "✅ <span class=\"font-mono\">Are you ready?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Użycie <strong>do/does/did</strong> z modalami.",
            "wrong": "❌ Do you can help?",
            "right": "✅ <span class=\"font-mono\">Can you help?</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Niepoprawna forma głównego czasownika po <strong>does</strong> lub <strong>did</strong>.",
            "wrong": "❌ Does she works here?",
            "right": "✅ <span class=\"font-mono\">Does she work here?</span>"
        },
        {
            "label": "Błąd 5",
            "color": "emerald",
            "title": "Dodawanie <strong>do</strong> w pytaniu o podmiot.",
            "wrong": "❌ Who did call you?",
            "right": "✅ <span class=\"font-mono\">Who called you?</span>"
        },
        {
            "label": "Błąd 6",
            "color": "indigo",
            "title": "Brak czasownika pomocniczego tam, gdzie jest potrzebny.",
            "wrong": "❌ She speaks English?",
            "right": "✅ <span class=\"font-mono\">Does she speak English?</span>"
        }
    ]
}

{
    "title": "11. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą opcję",
    "select_intro": "Wybierz poprawną formę pytania.",
    "selects": [
        {
            "label": "a) Are you happy? / b) Do you are happy? / c) You are happy?",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Where does she live? / b) Where she lives? / c) Does where she live?",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Can you help me? / b) Do you can help me? / c) You can help me?",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Who called you? / b) Who did call you? / c) Did who call you?",
            "prompt": "Która opcja jest poprawna?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Ćwiczenie 2. Utwórz pytanie",
    "input_intro": "Ułóż pytanie z podanego zdania.",
    "inputs": [
        {
            "before": "She speaks French. → ",
            "after": ""
        },
        {
            "before": "They are students. → ",
            "after": ""
        },
        {
            "before": "He can drive. → ",
            "after": ""
        },
        {
            "before": "She went to Paris. (Where...?) → ",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w pytaniu.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "You are ready?",
            "example_target": "Are you ready?"
        },
        {
            "original": "1. Do you are tired?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Where she lives?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Does he can swim?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "4. Who did call you?",
            "placeholder": "Popraw błąd"
        }
    ]
}

